for para in doc.paragraphs:
    text = para.text.strip()
    if text.startswith('6.3 '):
        current_section = '6.3'
    elif text.startswith('6.4 '):
        current_section = '6.4'
    elif text.startswith('第六章'):
        current_section = '其他'

    if current_section:
        chars_count[current_section] += len(text)

print('=== 字数统计 ===')
for section, count in chars_count.items():
    print(f'{section}: {count} 字符 (约 {count//2} 中文字)')

print()
print('=== 案例数量 ===')
case_count = 0
for para in doc.paragraphs:
    if '案例' in para.text and ('：' in para.text or ':' in para.text):
        case_count += 1
        print(f'  - {para.text[:50]}...')

print(f'\n共 {case_count} 个案例')

print()
print('=== 参考文献数量 ===')
ref_count = 0
for para in doc.paragraphs:
    if para.text.strip().startswith('[') and ']' in para.text:
        ref_count += 1

print(f'共 {ref_count} 条参考文献')
""}

